export type ReviewActionV2RequestParseResult<
  Operation extends ReviewActionV2OperationId,
> =
  | { readonly ok: true; readonly value: ReviewActionV2RequestMap[Operation] }
  | {
      readonly ok: false;
      readonly requestId?: string;
      readonly issues: readonly string[];
    };

export function parseReviewActionV2Request<
  Operation extends ReviewActionV2OperationId,
>(
  operationId: Operation,
  input: unknown,
): ReviewActionV2RequestParseResult<Operation> {
  const descriptor = reviewActionV2Operations.find(
    (item) => item.operationId === operationId,
  );
  if (!descriptor) throw new Error("review_action_v2_operation_unknown");
  if (!isRecord(input)) return { ok: false, issues: ["body_not_object"] };
  const requestId = readRequestId(input.requestId);
  const issues: string[] = [];
  const authorityFields = authorityFieldNames(descriptor.callerAuthority);
  const mutableFields =
    descriptor.mutability === "read" ||
    operationId === ReviewActionV2OperationId.ReviewRunAuthorize
      ? []
      : ["idempotencyKey", "requestBodyHash"];
  const authorizeFields =
    operationId === ReviewActionV2OperationId.ReviewRunAuthorize
      ? ["oidcToken", "supportedProtocols"]
      : [];
  const allowed = new Set([
    "protocolVersion",
    "schemaDigest",
    "requestId",
    ...authorityFields,
    ...mutableFields,
    ...authorizeFields,
    ...descriptor.requestFields.map((field) => field.name),
  ]);
  for (const key of Object.keys(input).sort()) {
    if (!allowed.has(key)) issues.push(`unknown_field:${key}`);
  }
  if (input.protocolVersion !== reviewActionV2PublishedProtocolVersion)
    issues.push("protocol_version_invalid");
  if (input.schemaDigest !== reviewActionV2PublishedSchemaDigest)
    issues.push("schema_digest_invalid");
  if (!requestId) issues.push("request_id_invalid");
  for (const field of authorityFields)
    validateField(field, "token", input[field], issues);
  for (const field of mutableFields)
    validateField(
      field,
      field === "requestBodyHash" ? "hash" : "identifier",
      input[field],
      issues,
    );
  if (operationId === ReviewActionV2OperationId.ReviewRunAuthorize) {
    validateField("oidcToken", "token", input.oidcToken, issues);
    validateProtocolOffers(input.supportedProtocols, issues);
  }
  for (const field of descriptor.requestFields)
    validateField(field.name, field.type, input[field.name], issues);
  for (const group of descriptor.allOrNoneRequestFieldGroups) {
    const nullCount = group.filter((field) => input[field] === null).length;
    if (nullCount !== 0 && nullCount !== group.length) {
      issues.push(`field_group_all_or_none:${group.join(",")}`);
    }
  }
  if (issues.length > 0 || !requestId) {
    return {
      ok: false,
      ...(requestId ? { requestId } : {}),
      issues: [...new Set(issues)].slice(0, 8),
    };
  }
  return { ok: true, value: input as ReviewActionV2RequestMap[Operation] };
}

export function canonicalizeReviewActionV2Request<
  Operation extends ReviewActionV2OperationId,
>(
  operationId: Operation,
  request: ReviewActionV2RequestMap[Operation],
): string {
  const parsed = parseReviewActionV2Request(operationId, request);
  if (!parsed.ok)
    throw new Error(
      `review_action_v2_request_invalid:${parsed.issues.join(",")}`,
    );
  const descriptor = reviewActionV2Operations.find(
    (item) => item.operationId === operationId,
  );
  if (!descriptor) throw new Error("review_action_v2_operation_unknown");
  const body = Object.fromEntries(
    descriptor.requestFields.map((field) => [
      field.name,
      (request as Record<string, unknown>)[field.name],
    ]),
  );
  return canonicalJson(body);
}

export function createReviewActionV2ErrorResponse(input: {
  readonly operationId: ReviewActionV2OperationId;
  readonly requestId: string;
  readonly serverTime: string;
  readonly errorCode: ReviewActionV2ProtocolErrorCode;
  readonly issues?: readonly string[];
}): ReviewActionV2ErrorResponse {
  const descriptor = reviewActionV2Operations.find(
    (item) => item.operationId === input.operationId,
  );
  const error = reviewActionV2ErrorRegistry.find(
    (item) => item.errorCode === input.errorCode,
  );
  if (
    !descriptor ||
    !error ||
    !descriptor.errorCodes.includes(input.errorCode as never)
  ) {
    throw new Error("review_action_v2_error_not_allowed");
  }
  if (
    !readRequestId(input.requestId) ||
    !Number.isFinite(Date.parse(input.serverTime))
  ) {
    throw new Error("review_action_v2_error_envelope_invalid");
  }
  return {
    protocolVersion: reviewActionV2PublishedProtocolVersion,
    schemaDigest: reviewActionV2PublishedSchemaDigest,
    requestId: input.requestId,
    serverTime: input.serverTime,
    error: {
      errorCode: input.errorCode,
      retryClass: toRetryClass(error.retryClass),
      details: {
        issues: [...new Set(input.issues ?? [input.errorCode])]
          .filter(Boolean)
          .slice(0, 8),
      },
    },
  };
}

export function createReviewActionV2ResultResponse<
  Operation extends ReviewActionV2OperationId,
>(input: {
  readonly operationId: Operation;
  readonly requestId: string;
  readonly serverTime: string;
  readonly result: ReviewActionV2ResultMap[Operation];
}): ReviewActionV2ResultEnvelope<ReviewActionV2ResultMap[Operation]> {
  const descriptor = reviewActionV2Operations.find(
    (item) => item.operationId === input.operationId,
  );
  if (
    !descriptor ||
    !descriptor.resultStatuses.includes(input.result.status as never)
  ) {
    throw new Error("review_action_v2_result_status_invalid");
  }
  if (
    !readRequestId(input.requestId) ||
    !Number.isFinite(Date.parse(input.serverTime))
  ) {
    throw new Error("review_action_v2_result_envelope_invalid");
  }
  return {
    protocolVersion: reviewActionV2PublishedProtocolVersion,
    schemaDigest: reviewActionV2PublishedSchemaDigest,
    requestId: input.requestId,
    serverTime: input.serverTime,
    result: input.result,
  };
}

const reviewActionV2ErrorRegistry = [
  {
    typeName: "InvalidRequest",
    errorCode: "invalid_request",
    retryClass: "never",
    httpStatus: 400,
  },
  {
    typeName: "InvalidAuthentication",
    errorCode: "invalid_authentication",
    retryClass: "never",
    httpStatus: 401,
  },
  {
    typeName: "Forbidden",
    errorCode: "forbidden",
    retryClass: "never",
    httpStatus: 403,
  },
  {
    typeName: "CapabilityDisabled",
    errorCode: "capability_disabled",
    retryClass: "never",
    httpStatus: 403,
  },
  {
    typeName: "NotFound",
    errorCode: "not_found",
    retryClass: "never",
    httpStatus: 404,
  },
  {
    typeName: "IdempotencyConflict",
    errorCode: "idempotency_conflict",
    retryClass: "never",
    httpStatus: 409,
  },
  {
    typeName: "ResourceGone",
    errorCode: "resource_gone",
    retryClass: "never",
    httpStatus: 410,
  },
  {
    typeName: "StalePrecondition",
    errorCode: "stale_precondition",
    retryClass: "never",
    httpStatus: 412,
  },
  {
    typeName: "LimitExceeded",
    errorCode: "limit_exceeded",
    retryClass: "never",
    httpStatus: 413,
  },
  {
    typeName: "InvariantViolation",
    errorCode: "invariant_violation",
    retryClass: "never",
    httpStatus: 422,
  },
  {
    typeName: "UnsupportedProtocol",
    errorCode: "unsupported_protocol",
    retryClass: "never",
    httpStatus: 426,
  },
  {
    typeName: "CapacityLimited",
    errorCode: "capacity_limited",
    retryClass: "same_request",
    httpStatus: 429,
  },
  {
    typeName: "AmbiguousOutcome",
    errorCode: "ambiguous_outcome",
    retryClass: "same_request",
    httpStatus: 500,
  },
  {
    typeName: "ServiceUnavailable",
    errorCode: "service_unavailable",
    retryClass: "read_only",
    httpStatus: 503,
  },
] as const;
const digestPattern = /^[a-f0-9]{64}$/;
const gitOidPattern = /^(?:[a-f0-9]{40}|[a-f0-9]{64})$/;
const decimalPattern = /^(0|[1-9][0-9]*)$/;
const identifierPattern = /^[A-Za-z0-9][A-Za-z0-9._:-]{0,255}$/;
const requestIdPattern = /^[A-Za-z0-9][A-Za-z0-9._:-]{0,127}$/;

function toRetryClass(value: string): ReviewActionV2RetryClass {
  switch (value) {
    case ReviewActionV2RetryClass.Never:
      return ReviewActionV2RetryClass.Never;
    case ReviewActionV2RetryClass.SameRequest:
      return ReviewActionV2RetryClass.SameRequest;
    case ReviewActionV2RetryClass.ReadOnly:
      return ReviewActionV2RetryClass.ReadOnly;
    default:
      throw new Error("review_action_v2_retry_class_unknown");
  }
}

function validateField(
  name: string,
  type: string,
  value: unknown,
  issues: string[],
): void {
  const nullable = type.startsWith("nullable_");
  if (nullable && value === null) return;
  const base = nullable ? type.slice("nullable_".length) : type;
  let valid = false;
  if (base === "boolean") valid = typeof value === "boolean";
  else if (base === "hash")
    valid = typeof value === "string" && digestPattern.test(value);
  else if (base === "git_oid")
    valid = typeof value === "string" && gitOidPattern.test(value);
  else if (base === "decimal")
    valid = typeof value === "string" && decimalPattern.test(value);
  else if (base === "identifier")
    valid = typeof value === "string" && identifierPattern.test(value);
  else if (base === "positive_integer")
    valid = Number.isSafeInteger(value) && (value as number) > 0;
  else if (base === "non_negative_integer")
    valid = Number.isSafeInteger(value) && (value as number) >= 0;
  else if (base === "timestamp")
    valid = typeof value === "string" && Number.isFinite(Date.parse(value));
  else if (base === "token")
    valid =
      typeof value === "string" &&
      value.length > 0 &&
      value.length <= 32768 &&
      /^\S+$/u.test(value);
  else if (base === "string")
    valid =
      typeof value === "string" && value.length > 0 && value.length <= 1024;
  else if (base === "canonical_json")
    valid = typeof value === "string" && isCanonicalJson(value);
  else if (base === "hash_array")
    valid =
      Array.isArray(value) &&
      value.length <= 256 &&
      value.every(
        (item) => typeof item === "string" && digestPattern.test(item),
      );
  else if (base === "identifier_array")
    valid =
      Array.isArray(value) &&
      value.length <= 256 &&
      value.every(
        (item) => typeof item === "string" && identifierPattern.test(item),
      );
  if (!valid) issues.push(`field_invalid:${name}`);
}

function validateProtocolOffers(value: unknown, issues: string[]): void {
  if (!Array.isArray(value) || value.length === 0 || value.length > 8) {
    issues.push("protocol_offers_invalid");
    return;
  }
  const identities = new Set<string>();
  for (const candidate of value) {
    if (
      !isRecord(candidate) ||
      Object.keys(candidate).sort().join(",") !==
        "protocolVersion,schemaDigest" ||
      typeof candidate.protocolVersion !== "string" ||
      typeof candidate.schemaDigest !== "string" ||
      !digestPattern.test(candidate.schemaDigest)
    ) {
      issues.push("protocol_offer_invalid");
      continue;
    }
    const identity = `${candidate.protocolVersion}:${candidate.schemaDigest}`;
    if (identities.has(identity)) issues.push("protocol_offer_duplicate");
    identities.add(identity);
  }
}

function authorityFieldNames(
  authority: ReviewActionV2CallerAuthority,
): readonly string[] {
  if (authority === ReviewActionV2CallerAuthority.FreshScmOidc) return [];
  if (
    authority ===
    ReviewActionV2CallerAuthority.CurrentAuthorizationAndFreshSameRunOidc
  )
    return ["authorizationToken"];
  if (authority === ReviewActionV2CallerAuthority.RunAuthorization)
    return ["authorizationToken"];
  if (
    authority ===
    ReviewActionV2CallerAuthority.RunAuthorizationAndLeaseCapability
  )
    return ["authorizationToken", "leaseCapability"];
  if (
    authority ===
    ReviewActionV2CallerAuthority.RunAuthorizationAndPublicationPermit
  )
    return ["authorizationToken"];
  if (authority === ReviewActionV2CallerAuthority.LeaseCapability)
    return ["leaseCapability"];
  throw new Error("review_action_v2_caller_authority_unknown");
}

function readRequestId(value: unknown): string | null {
  return typeof value === "string" && requestIdPattern.test(value)
    ? value
    : null;
}

function isCanonicalJson(value: string): boolean {
  try {
    return canonicalJson(JSON.parse(value)) === value;
  } catch {
    return false;
  }
}

function canonicalJson(value: unknown): string {
  if (Array.isArray(value)) return `[${value.map(canonicalJson).join(",")}]`;
  if (isRecord(value))
    return `{${Object.keys(value)
      .sort()
      .map((key) => `${JSON.stringify(key)}:${canonicalJson(value[key])}`)
      .join(",")}}`;
  return JSON.stringify(value);
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}
